module top_module(
  input clk,
  input reset,
  input enable,
  input d,
  output reg q
);reg q_prev;

  always @(posedge clk) begin
    if (reset) begin
      q_prev <= 1'b0;
    end else if (enable) begin
      q_prev <= d;
    end else begin
      q_prev <= q;
    end
  end

  assign q = q_prev;

endmodule
